import { useWireFrameDocumentStore } from "@/stores/WireFrameDocumenStore";
import { useEditionStore } from "@/stores/EditionStore";
import { computed } from "vue";

function getSelectedElements() {
  const wireFrameDocumentStore = useWireFrameDocumentStore();
  const editionStore = useEditionStore();
  const { targets } = editionStore;
  return computed(() => {
    const newArray: ElementInterface[] = [];
    targets.forEach((element) => {
      const elementFinded = wireFrameDocumentStore.getElementById(element.id);
      if (elementFinded) {
        newArray.push(elementFinded);
      }
    });

    return newArray;
  });
}

export { getSelectedElements };
