<!-- eslint-disable vue/no-mutating-props -->
<!-- TODO valeur par defaut = arial -->
<template>
  <div>
    <label class="label" v-if="props.label">{{ label }}</label>
    <InputSelect
      :options="options"
      :actualValue="valueTodisplay"
      :onChangeCallback="changeHandler"
    />

    <IconsSvg v-if="props.canReset" @click="deleteProperty" :icon="svgReset" />
  </div>
</template>

<script setup lang="ts">
import { computed, type PropType } from "vue";
import IconsSvg from "./IconsSvg.vue";
import svgReset from "@/DesignSystem/Icons/List/Reset";
import { handlerProperty } from "./composables/handlerProperty";
import InputSelect from "@/DesignSystem/Form/InputSelect.vue";

const props = defineProps({
  label: String,
  properties: Object,
  propertyName: String,
  id: String,
  canReset: Boolean,
  options: {
    type: Array as PropType<Array<string>>,
    required: true,
  },
});

const valueTodisplay = computed(() => {
  if (
    props.properties != undefined &&
    props.propertyName != undefined &&
    props.properties[props.propertyName] != undefined
  ) {
    return props.properties[props.propertyName];
  }

  return "";
});

function changeHandler(value: string) {
  handlerProperty(props.propertyName as string, value);
}

function deleteProperty() {
  if (
    props.properties != undefined &&
    props.propertyName != undefined &&
    props.properties[props.propertyName] != undefined
  ) {
    delete props.properties[props.propertyName];
  }
}
</script>

<style scoped>
.label {
  color: var(--white);
  display: grid;
  width: 100%;
  align-items: center;
  text-align: left;
}
</style>
